const body = $json.body || $json;

return [{
  json: {
    finding_id: body.finding_id,
    question: body.question || "How do I fix this vulnerability?",
    finding: body.finding || {},
    source_context: body.source_context || ""
  }
}];

const f = $json.finding || {};

const prompt = `
You are an AI DevSecOps remediation assistant.

Vulnerability:
- Finding ID: ${$json.finding_id}
- Tool: ${f.tool || ""}
- Severity: ${f.severity || ""}
- Type: ${f.type || ""}
- Title: ${f.title || ""}
- File or URL: ${f.file_or_url || ""}
- Line: ${f.line || ""}
- Suggested fix from scanner: ${f.suggested_fix || ""}

Source code context:
${$json.source_context || "No source code context provided."}

Developer question:
${$json.question}

Please answer with:
1. Root cause
2. Security impact
3. Step-by-step fix
4. Secure code example if possible
5. How to verify the fix
`;

return [{
  json: {
    ...$json,
    ai_prompt: prompt
  }
}];

const previous = $("Load AI Config").first().json;
const provider = previous.ai_provider;

let answer = "";

if (provider === "ollama") {
  answer =
    $json.response ||
    $json.body?.response ||
    "";
}

else if (provider === "openai") {
  answer =
    $json.choices?.[0]?.message?.content ||
    $json.body?.choices?.[0]?.message?.content ||
    "";
}

else if (provider === "anthropic") {
  const content = $json.content || $json.body?.content || [];
  answer = content
    .map(item => item.text || "")
    .join("\n")
    .trim();
}

return [
  {
    json: {
      finding_id: previous.finding_id,
      question: previous.question,
      ai_provider: provider,
      answer,
      created_at: new Date().toISOString()
    }
  }
];

const provider = String($env.AI_PROVIDER || "ollama").toLowerCase();

const temperature = Number($env.AI_TEMPERATURE || 0.2);
const maxTokens = Number($env.AI_MAX_TOKENS || 700);

let ai_url = "";
let ai_headers = {
  "Content-Type": "application/json"
};
let ai_body = {};

if (provider === "ollama") {
  const baseUrl = String($env.OLLAMA_BASE_URL || "http://host.docker.internal:11434").replace(/\/$/, "");
  const model = String($env.OLLAMA_MODEL || "qwen2.5:3b");

  ai_url = `${baseUrl}/api/generate`;

  ai_body = {
    model,
    prompt: $json.ai_prompt,
    stream: false,
    options: {
      temperature,
      num_predict: maxTokens
    }
  };
}

else if (provider === "openai") {
  const baseUrl = String($env.OPENAI_COMPATIBLE_BASE_URL || "").replace(/\/$/, "");
  const apiKey = String($env.OPENAI_COMPATIBLE_API_KEY || "");
  const model = String($env.OPENAI_COMPATIBLE_MODEL || "gpt-4o-mini");

  ai_url = `${baseUrl}/chat/completions`;

  ai_headers = {
    "Content-Type": "application/json",
    "Authorization": `Bearer ${apiKey}`
  };

  ai_body = {
    model,
    messages: [
      {
        role: "system",
        content: "You are an AI DevSecOps remediation assistant."
      },
      {
        role: "user",
        content: $json.ai_prompt
      }
    ],
    temperature,
    max_tokens: maxTokens
  };
}

else if (provider === "anthropic") {
  const apiKey = String($env.ANTHROPIC_API_KEY || "");
  const model = String($env.ANTHROPIC_MODEL || "claude-3-5-sonnet-latest");

  ai_url = "https://api.anthropic.com/v1/messages";

  ai_headers = {
    "Content-Type": "application/json",
    "x-api-key": apiKey,
    "anthropic-version": "2023-06-01"
  };

  ai_body = {
    model,
    max_tokens: maxTokens,
    temperature,
    messages: [
      {
        role: "user",
        content: $json.ai_prompt
      }
    ]
  };
}

else {
  throw new Error(`Unsupported AI_PROVIDER: ${provider}`);
}

return [
  {
    json: {
      ...$json,
      ai_provider: provider,
      ai_url,
      ai_headers,
      ai_body
    }
  }
];
